"""
MKT Christ — Mark chapters 1–2
Output: data/commentary/mkt-christ/mark.json
Run: python3 scripts/zc-christ-mark-1-2.py

Mark's Christology in chs 1–2: Son of God (1:1, 1:11), the Coming One who
baptizes with Spirit (1:7–8), the new Adam in the wilderness (1:12–13), the
divine forgiver (2:5–10), and the Bridegroom (2:19–20). Every verse is covered;
merge_comm skips the 1:1, 1:11, 1:15 entries already written by a prior agent.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK_CH1_2 = {
  "1": {
    "1": '<p>A direct revelation: the opening declaration names Jesus as Christ (the Messiah, the anointed one promised in Israel\'s scriptures) and Son of God (the one who stands in the unique filial relationship to the Father). Every verse in Mark is the unpacking of this single sentence — the narrative content of what it means that this person has come.</p>',
    "2": '<p>A direct quotation applied to John: &ldquo;I will send my messenger ahead of you, who will prepare your way&rdquo; (Mal 3:1). The one before whose face the messenger goes is the Lord himself — Christ steps into the role that Malachi reserves for YHWH returning to his temple. The composite citation (Mal 3:1 + Isa 40:3) frames the Baptist\'s entire ministry as forerunner to the divine presence arriving in Jesus.</p>',
    "3": '<p>A direct quotation from Isa 40:3: &ldquo;a voice crying in the wilderness, Prepare the way of the Lord.&rdquo; Isaiah\'s &ldquo;Lord&rdquo; is YHWH returning from Babylon to restore his people; Mark\'s Gospel applies the title to Jesus, identifying him as the Lord whose way John prepares. The wilderness setting links John to Israel\'s covenant history and positions Jesus\'s ministry as the new Exodus.</p>',
    "4": '<p>A theme of covenant renewal: John\'s baptism of repentance for the forgiveness of sins anticipates the one who will accomplish what the baptism signifies — actual forgiveness through his death (14:24). The forerunner\'s rite points forward to the superior reality: the Coming One does not merely symbolize forgiveness but effects it.</p>',
    "5": '<p>A theme of Israel gathering: all Judea and Jerusalem coming out to John\'s baptism mirrors the covenant assembly of the people — but John himself points to one coming who will baptize with the Spirit rather than water. The mass response to the forerunner signals the eschatological moment; the crowd that gathers for John will soon encounter the one John prepares them for.</p>',
    "6": '<p>A type: John\'s clothing (camel\'s hair, leather belt) intentionally echoes Elijah the Tishbite (2 Kgs 1:8). Malachi 4:5 promised Elijah\'s return before the great day of the Lord; Jesus later confirms that John is this Elijah (9:13). The type works in two directions: John is the Elijah who returns, and Jesus is the Lord whose day of coming Elijah was to announce.</p>',
    "7": '<p>A direct revelation: the Coming One is &ldquo;mightier than I,&rdquo; whose sandal John is unworthy to stoop and untie. The sandal-bearer was the lowest slave function — John places himself below a slave-rank relative to Christ. The Christological weight is the word &ldquo;mightier&rdquo; (ischuroteros) — it is the same word used in 3:27 when Jesus describes himself as the &ldquo;stronger one&rdquo; who binds Satan. John announces the divine Warrior who will conquer the enemy of humanity.</p>',
    "8": '<p>A direct revelation: &ldquo;He will baptize you with the Holy Spirit.&rdquo; Only God can give the Holy Spirit (Joel 2:28–29; Ezek 36:26–27); John\'s announcement that the Coming One will do so is an implicit divine claim. The Spirit-baptism is enacted at Pentecost (Acts 2) and is the defining mark of the new covenant community. Christ does what only God does: he pours out the Spirit promised through the prophets.</p>',
    "9": '<p>A revelation of God: Jesus comes from Nazareth in Galilee to be baptized by John — the sinless one undergoing a repentance rite, identifying with those he came to save. The Baptist\'s water-baptism requires repentance he does not need; his submission to it is the first act of the &ldquo;ransom for many&rdquo; movement (10:45), taking on himself what belongs to others. The incarnate Lord enters fully into the human condition of needing restoration to God.</p>',
    "10": '<p>A direct revelation: heaven is torn open and the Spirit descends on Jesus like a dove. Mark\'s verb &ldquo;torn&rdquo; (schizomenous) is violent — the same word used for the temple veil tearing at his death (15:38). The heavens that were closed since Malachi\'s last prophecy are rent open at the Son\'s baptism; the Spirit who hovered over the creation waters (Gen 1:2) anoints the one who will inaugurate the new creation.</p>',
    "11": '<p>A direct revelation: &ldquo;You are my Son, whom I love; with you I am well pleased.&rdquo; The Father\'s declaration fuses Ps 2:7 (the royal Messiah) and Isa 42:1 (the Servant in whom God delights), naming Jesus as the one who holds both identities. The royal Son is the Suffering Servant; every subsequent act of authority (exorcisms, healings) and every act of self-giving (the passion) develops the meaning of this dual declaration.</p>',
    "12": '<p>A type: the Spirit immediately drives Jesus into the wilderness — the site of Israel\'s forty-year testing. As Israel was tested in the wilderness for forty years (Num 32:13; Deut 8:2) and failed, Jesus is tested forty days and does not fail. He is the new Israel who succeeds where the nation failed, absorbing their judgment and fulfilling their covenant faithfulness on behalf of the many.</p>',
    "13": '<p>A type of the new Adam: Jesus is with the wild animals and the angels serve him — an inversion of the Fall. Adam in the garden was given dominion over animals and was served by unfallen creation; he lost it through disobedience. In the wilderness, Christ begins to restore it: the wild animals do not threaten him and the angels minister to him, signaling that in his person the curse is being reversed and the creation mandate reclaimed.</p>',
    "14": '<p>A theme of divine timing: after John is arrested, Jesus comes into Galilee — Mark presents the Baptist\'s imprisonment as the divinely appointed moment for Christ\'s public ministry to begin. The pattern (forerunner silenced, then the one he announced steps forward) recurs at a deeper level at Calvary: Christ is silenced in death, and the resurrection inaugurates the age of Spirit-proclamation through the church.</p>',
    "15": '<p>A direct revelation: &ldquo;The time is fulfilled and the kingdom of God has come near; repent and believe in the good news.&rdquo; Christ is not merely the herald of the kingdom but its embodiment — the kingdom arrives in his person. &ldquo;The time is fulfilled&rdquo; (peplērotai ho kairos) names his arrival as the fulfillment of the Danielic appointed moment (Dan 7:22). The call to believe in the good news is a call to trust his person, not merely accept a doctrine.</p>',
    "16": '<p>A revelation of God: Jesus walks by the Sea of Galilee and sees Simon and Andrew — the sovereign initiative is entirely his. He is not sought; he seeks. The pattern continues the OT theme of God initiating the covenant from his own freedom (Deut 7:6–7; Isa 65:1), now exercised in Christ\'s personal summons of individuals into the messianic community.</p>',
    "17": '<p>A direct revelation of mission: &ldquo;Follow me, and I will make you become fishers of men.&rdquo; Christ speaks with the authority that belongs to the one who defines people\'s vocation. The &ldquo;follow me&rdquo; formula in Mark is not an invitation but a command that creates obedience — the same creative-word power that called light from darkness now calls disciples from their nets.</p>',
    "18": '<p>A revelation of Christ\'s authority: &ldquo;immediately they left their nets and followed him&rdquo; — the instant obedience is not psychological explanation but theological testimony. Mark frequently uses &ldquo;immediately&rdquo; (euthys) to signal that Jesus\'s authority requires no delay, argument, or persuasion. The disciples\' action reveals who called them, not what they achieved.</p>',
    "19": '<p>A theme of the new community: Jesus calls James and John from the boat with their father Zebedee. The leaving of the father — the seat of family authority, lineage, and livelihood — to follow Christ marks the messianic community as one where Christ\'s call supersedes every natural bond (cf. 3:31–35; 10:29–30). Discipleship is ordered by a higher loyalty than family.</p>',
    "20": '<p>A revelation of Christ\'s authority: they left their father in the boat with the hired servants and followed him. The hired servants remain; the sons depart. Mark\'s terse narration makes no comment — the authority of the call is self-evident in the response. The disciples who abandon father and livelihood for Christ\'s sake will receive back hundredfold (10:30).</p>',
    "21": '<p>A revelation of Christ\'s identity through setting: Jesus enters the synagogue on the Sabbath and teaches. The synagogue is the seat of Israel\'s Torah instruction; the Sabbath is the covenant sign. Jesus teaching in both contexts claims the authority to interpret and embody what the Torah and the Sabbath point to — a claim the scribal tradition had never made on its own behalf.</p>',
    "22": '<p>A direct revelation: &ldquo;he taught as one who had authority, and not as the scribes.&rdquo; The scribes derived authority by citing predecessors (&ldquo;Rabbi X says…&rdquo;); Jesus speaks in his own name (&ldquo;I say to you,&rdquo; 2:28). The crowd\'s astonishment identifies the category — this is not superior scholarship but a fundamentally different kind of authority. The only precedent is divine speech (cf. Isa 45:18, &ldquo;thus says the Lord&rdquo;).</p>',
    "23": '<p>A revelation of the spiritual realm: a man with an unclean spirit is in the synagogue — the religious center is not immune to demonic presence. The drama that follows is Mark\'s first exorcism: Christ enters sacred space and immediately the demonic is unmasked. His presence exposes what was hidden; the arrival of the holy Son of God forces the demonic into confrontation.</p>',
    "24": '<p>A direct revelation from the demonic: &ldquo;I know who you are — the Holy One of God.&rdquo; The demonic realm perceives what the human characters in Mark spend the whole Gospel learning. &ldquo;Holy One of God&rdquo; is a title that points to divine consecration (cf. Ps 106:16; Isa 40:25) — the demons recognize that the one confronting them is not a human authority figure but the divine Agent whose holiness destroys uncleanness by its presence.</p>',
    "25": '<p>A revelation of Christ\'s authority: &ldquo;Be silent and come out of him.&rdquo; The command requires two things — silence (the messianic secret) and departure. Christ does not pray, perform a ritual, or invoke a higher name; he commands in his own name and the spirit obeys. The authority is intrinsic, not delegated. The same voice that stills the sea (4:39) stills the spirit here.</p>',
    "26": '<p>A theme of Christ overcoming evil: the unclean spirit convulses the man and cries out before departing — the exit is violent but complete. Christ\'s victory over the demonic in Mark is consistently total; the enemy does not negotiate or partially comply. Every exorcism in Mark is a microcosm of the larger conflict: Satan\'s plundering (3:27) that culminates in the cross where the strong man is bound decisively.</p>',
    "27": '<p>A direct revelation through the crowd\'s question: &ldquo;What is this? A new teaching with authority! He commands even the unclean spirits and they obey him.&rdquo; The crowd\'s astonishment is Mark\'s Christological testimony — the question &ldquo;what is this?&rdquo; (ti estin touto) is the right question, and Mark\'s Gospel is the answer. The new teaching and the authority over spirits belong together: he teaches what he enacts, and enacts what he teaches.</p>',
    "28": '<p>A theme of the kingdom\'s spread: news of Jesus spreads immediately throughout all of Galilee. The proclamation that reaches the people is not their own initiative but the overflow of his authority. Mark\'s Gospel is structured as the spreading of this authority — from Galilee to Jerusalem, and after the resurrection, to all nations (cf. 13:10; 14:9).</p>',
    "29": '<p>A theme of the messianic age inbreaking: Jesus enters Simon\'s house after the synagogue. The movement from public worship space to private household signals that his authority and care are not confined to formal religious settings — the healing that follows (vv.30–31) is domestic, intimate, and immediate. The kingdom comes to wherever he is present.</p>',
    "30": '<p>A theme of intercession: Simon\'s mother-in-law lies sick with fever, and they immediately tell Jesus about her. The act of bringing the need to Christ is the pattern of prayer Mark\'s narrative models throughout — the disciples as intercessors, the crowd as witnesses. The one who heals is also the one to whom the sick are brought in faith.</p>',
    "31": '<p>A revelation of Christ\'s compassion: he took her by the hand, raised her up, and the fever left. The physical gesture — taking her hand — recurs at the raising of Jairus\'s daughter (5:41) and the transfiguration (9:27). The healing touch precedes the verbal command in this case; Christ\'s contact with the sick does not contaminate him but restores them. The raised-up (ēgeiren) language anticipates the resurrection vocabulary that Mark will apply to Jesus himself.</p>',
    "32": '<p>A theme of the messianic age: at sundown (when Sabbath travel restrictions ended) the whole city gathers with sick and demon-possessed. The crowds coming to Jesus enact the eschatological ingathering prophesied in Isa 35:5–6 — the blind see, the deaf hear, the lame walk. Jesus is the place where the nation\'s healing promised in the prophets is taking place.</p>',
    "33": '<p>A theme of universal access: the whole city was gathered at the door. No category of person is excluded from approaching Jesus — the sick and the demon-possessed alike come. The door at which the crowd gathers anticipates the new temple imagery: Christ is the threshold of access to God. The one who stands at the door and knocks (in the Apocalypse, 3:20) is here receiving all who come to him.</p>',
    "34": '<p>A theme of the Messianic Secret: Jesus heals many and casts out demons, but &ldquo;he would not permit the demons to speak, because they knew him.&rdquo; The silencing of supernatural testimony is the Messianic Secret in its purest form — Jesus refuses to be proclaimed by demonic witnesses whose testimony would be politically (or theologically) distorting. The correct confession of his identity must be tied to the cross; premature disclosure distorts.</p>',
    "35": '<p>A revelation of Christ\'s sonship: rising very early, Jesus goes to a desolate place and prays. The one through whom all things were made (John 1:3) prays to the Father — the eternal Son\'s communion with the Father expressed in his incarnate prayer life. Every prayer of Jesus in Mark signals the filial relationship at the heart of his identity; the disciples who follow him are called into this same relationship (14:36).</p>',
    "36": '<p>A theme of the messianic community: Simon and those with him searched for Jesus. The disciples are already defined as those who seek Christ — but their expectation (v.37, &ldquo;everyone is looking for you&rdquo;) reflects the crowd\'s desire rather than Jesus\'s mission. The gap between what the disciples expect and what Jesus announces (v.38) is the pedagogical heart of Mark\'s discipleship narrative.</p>',
    "37": '<p>A theme of Christ being sought: &ldquo;everyone is looking for you.&rdquo; The disciples report crowd enthusiasm as if it should determine Jesus\'s next action; instead he announces departure to other towns. His mission is not defined by popular demand but by the Father\'s purpose (v.38, &ldquo;for this I came out&rdquo;). Christ\'s sense of divine mission overrides all crowd-pleasing possibilities throughout Mark.</p>',
    "38": '<p>A direct revelation of mission consciousness: &ldquo;Let us go to the next towns, that I may preach there also, for that is why I came out.&rdquo; The phrase &ldquo;for this I came out&rdquo; (eis touto gar exēlthon) reveals Christ\'s own understanding of his mission — he came not to build a local following but to proclaim throughout Galilee. The pre-existent Son who &ldquo;came out&rdquo; from the Father (John 8:42, 16:28) uses the same coming-out language here for his Galilean departure.</p>',
    "39": '<p>A theme of the kingdom advancing: Jesus goes throughout all Galilee preaching in synagogues and casting out demons — the paired ministry of proclamation and liberation is the form the kingdom takes in Mark\'s opening. The synagogues represent Israel\'s covenant structures; the demon-expulsions represent the reclamation of occupied territory. Both ministries declare the same truth: the Lord has come and the enemy is being defeated.</p>',
    "40": '<p>A type of the spiritual condition of humanity: the leper who comes and kneels before Jesus represents the condition of all who approach Christ — unclean under the law, excluded from community, without access to God. The leprosy that made one untouchable and unable to worship (Lev 13–14) is the condition of sin that separates from the holy. The leper\'s &ldquo;if you will, you can make me clean&rdquo; is the prayer of faith from the one who knows his need.</p>',
    "41": '<p>A revelation of Christ\'s compassion and authority: moved with compassion, Jesus stretches out his hand and touches the leper — the act that made the toucher ritually unclean under Levitical law. Instead of defilement transferring from the leper to Jesus, cleanness transfers from Jesus to the leper. The one who will &ldquo;become sin&rdquo; at the cross (2 Cor 5:21) already patterns this substitutionary movement: he touches what is unclean and absorbs it into his own holiness rather than becoming contaminated.</p>',
    "42": '<p>A revelation of Christ\'s healing power: &ldquo;immediately the leprosy left him and he was made clean.&rdquo; The healing is total and instantaneous — no gradual improvement, no partial recovery. The messianic healings prophesied in Isaiah (35:5–6; 61:1) are enacted with the immediacy that characterizes divine creative action. The word that said &ldquo;Let there be light&rdquo; is the same word that says &ldquo;Be clean.&rdquo;</p>',
    "43": '<p>A theme of the Messianic Secret: Jesus warns the man sternly and immediately sends him away. The urgency of the command (embrimēsamenos — a word of intense emotion) signals that Jesus does not want his identity broadcast in a form that would create political-messianic expectations before the cross. The secrecy protects the proper understanding: he is the Messiah who suffers, not the revolutionary king the crowds would make him.</p>',
    "44": '<p>A revelation of Christ fulfilling Torah: &ldquo;show yourself to the priest and offer for your cleansing what Moses commanded.&rdquo; Jesus directs the cleansed leper to the Levitical procedures of Lev 14 — he does not abolish the Torah\'s cleansing mechanism but fulfills it. The healed man\'s priestly examination is the legal certification of what Christ has already accomplished. At the cross, Christ fulfills every purification the Torah prescribed but could not effect.</p>',
    "45": '<p>A theme of the gospel spreading beyond control: the man proclaims freely what Jesus commanded him not to, so that Jesus can no longer enter a town openly. The paradox runs throughout Mark: the one whose identity the Messianic Secret tries to conceal is the one the cosmos cannot contain. The leper who could not enter towns because of his disease now moves freely while Jesus cannot — the inversion anticipates the cross: he who was put outside the city (Heb 13:12) opens the city to all who were excluded.'
  },
  "2": {
    "1": '<p>A theme of Christ as the center of community: &ldquo;it was reported that he was at home&rdquo; — the house becomes the gathering point for Capernaum. The domestication of the messianic ministry (Jesus &ldquo;at home&rdquo; in a village house) is part of Mark\'s incarnational emphasis: the Son of God is present in ordinary spaces, not primarily in temple or wilderness. The word spreads because his presence draws people.</p>',
    "2": '<p>A revelation of Christ as teacher: so many gathered that there was no room even at the door, and &ldquo;he was speaking the word to them.&rdquo; The word (logos) in Mark refers specifically to the gospel proclamation — the announcement of the kingdom. Christ speaks the word that heals (1:25, 4:39) and the word that creates faith (4:20). The overcrowded house is the first image of what the gathered church will look like around the word.</p>',
    "3": '<p>A theme of persistence in seeking Christ: four men carry the paralytic to Jesus. The narrative detail — the number of carriers, the implied difficulty, the determination — is testimony to the faith that brings others to Christ. The paralytic cannot come himself; others bring him. This corporate intercession and effort is the pattern of the missionary church: those who cannot yet come to Christ are carried to him by those who can.</p>',
    "4": '<p>A revelation of Christ\'s healing through faith: unable to reach Jesus because of the crowd, they dig through the roof and lower the mat. Mark\'s account of the roof-breaking is unapologetic about the ingenuity required to get to Christ — no obstacle is insurmountable when faith is driving. The parallel with the church breaking through every cultural and social barrier to bring the gospel to those who cannot reach it is not allegorical but structural: this is what faith-driven mission looks like.</p>',
    "5": '<p>A direct revelation: seeing their faith, Jesus says to the paralytic, &ldquo;Son, your sins are forgiven.&rdquo; Christ speaks forgiveness on his own authority — not &ldquo;God forgives you&rdquo; but a direct declarative that positions himself as the one whose word effects the forgiveness. The address &ldquo;son&rdquo; (teknon) is intimate and restoring. The Christological argument that follows (vv.6–10) shows that Mark intends this forgiveness-claim as the central revelation of the pericope.</p>',
    "6": '<p>A revelation of Christ\'s knowledge through the scribes\' question: some scribes sitting there reason in their hearts. The question they do not voice — &ldquo;why does this man speak like this?&rdquo; — is the question Mark wants his audience to sit with. The scribes are not wrong that forgiving sins is a divine prerogative; they are wrong that Jesus is not divine. Their silent reasoning is the theological problem the miracle resolves.</p>',
    "7": '<p>A direct revelation through scribal objection: &ldquo;Who can forgive sins but God alone?&rdquo; The scribes have identified the correct category — forgiveness belongs to God alone (Isa 43:25; Mic 7:18). Their objection is theologically precise; their conclusion (Jesus is blaspheming) is wrong because they have not accepted what Mark\'s opening verse announced: this man is the Son of God. The objection is Mark\'s clearest statement that Jesus\'s forgiveness is a claim to divine identity, not merely priestly function.</p>',
    "8": '<p>A revelation of Christ\'s omniscience: Jesus &ldquo;immediately perceived in his spirit&rdquo; what the scribes were reasoning in their hearts. Divine knowledge of human thoughts is an attribute of YHWH throughout the OT (Ps 139:2; Jer 17:10); Jesus exercises it naturally, without invocation or revelation from outside himself. The God who searches hearts is present in the one who reads the scribes\'s unspoken objections.</p>',
    "9": '<p>A revelation of Christ through his rhetorical question: &ldquo;Which is easier, to say &lsquo;your sins are forgiven&rsquo; or to say &lsquo;rise and walk&rsquo;?&rdquo; The question is not about which is simpler to utter but which is harder to fake — forgiveness is unverifiable, healing is not. Jesus escalates from the unverifiable to the verifiable, demonstrating that the one who can do the harder thing (physically heal) has demonstrated authority to do the easier-to-say thing (forgive). The logic requires that the two acts come from the same authority.</p>',
    "10": '<p>A direct revelation: &ldquo;the Son of Man has authority on earth to forgive sins.&rdquo; The Danielic Son of Man who received universal dominion from the Ancient of Days (Dan 7:13–14) exercises that authority not in the apocalyptic clouds but in Capernaum, forgiving a paralytic. The &ldquo;on earth&rdquo; is theologically crucial: the eschatological reign has entered the present; the future has broken into the now through the Son\'s presence.</p>',
    "11": '<p>A revelation of Christ validating his authority: &ldquo;Rise, take up your mat and walk.&rdquo; The healing is the public demonstration of the private forgiveness — the invisible made visible. Every healing miracle in Mark functions as a signpost to something greater: the physical restoration is real but secondary to the spiritual reality it announces. Christ\'s authority over the body is inseparable from his authority over sin, because both disorders flow from the same root (human alienation from God).</p>',
    "12": '<p>A theme of glorifying God: the crowd is amazed and glorifies God, saying &ldquo;we never saw anything like this.&rdquo; Their amazement is the appropriate response to the unprecedented — no scribe, prophet, or priest had spoken forgiveness on their own authority and then confirmed it by healing. The crowd glorifies God rather than Jesus, but Mark has already established that glorifying the one who does God\'s work is glorifying the God who sent him.</p>',
    "13": '<p>A theme of the kingdom in all spaces: Jesus goes out again beside the sea, and the crowd comes to him. The sea of Galilee (the commercial and fishing hub of the region) is as much a place of teaching as the synagogue — Christ does not confine his kingdom proclamation to sacred spaces. The lake, the hillside, the road, and the house are all venues where the one who embodies the kingdom teaches.</p>',
    "14": '<p>A revelation of Christ\'s sovereign call: Jesus sees Levi son of Alphaeus sitting at the tax collector\'s booth and says, &ldquo;Follow me&rdquo; — and he rose and followed him. The tax collector was considered a collaborator with Rome and ritually impure through daily contact with Gentile coinage; no rabbi would have chosen him as a disciple. Christ\'s call crosses every social and ritual boundary. The sovereign call creates obedience where it would be least expected, because it is not based on the disciple\'s qualification but the Caller\'s authority.</p>',
    "15": '<p>A revelation of Christ\'s mission in practice: Jesus reclines at table in Levi\'s house with many tax collectors and sinners. Table fellowship in Second Temple Judaism was an act of covenant solidarity — you ate with those you accepted. Jesus\'s table practice extends that solidarity to the ritually excluded and socially despised. The table he sets anticipates the table of the new covenant (14:22–24) where the excluded are invited in through his own body and blood.</p>',
    "16": '<p>A theme of challenge and Christological clarification: the Pharisees ask the disciples why Jesus eats with tax collectors and sinners. The question is theologically pointed: holiness in their framework meant separation from the unclean. Jesus\'s answer (v.17) redefines holiness as compassionate movement toward the unclean — a redefinition that reflects his own identity as the Holy One of God who touches lepers and forgives sinners.</p>',
    "17": '<p>A direct revelation of mission: &ldquo;those who are well have no need of a physician, but those who are sick. I have not come to call the righteous but sinners.&rdquo; Christ defines his mission in terms of the physician who goes to the sick — not waiting for them to become healthy before attending to them. The &ldquo;I came&rdquo; language echoes v.38 of chapter 1: Christ has a mission-consciousness that precedes the Galilean ministry. He is the Healer of what no human physician can touch.</p>',
    "18": '<p>A theme of Christ as the new wine: the disciples of John and of the Pharisees fast, but Jesus\'s disciples do not. The contrast is not about the practice of fasting per se but about the eschatological moment — fasting belongs to the time of absence, longing, and mourning. The presence of Christ is the time of the wedding; the old disciplines of longing are superseded while the Bridegroom is present.</p>',
    "19": '<p>A direct revelation: &ldquo;Can the wedding guests fast while the bridegroom is with them?&rdquo; The Bridegroom is a Messianic title in the Jewish tradition (Isa 62:5; Jer 33:11; cf. John 3:29) — the marriage of God to his people in the eschatological age. Jesus claims the Bridegroom identity for himself: his presence is the fulfillment of Israel\'s covenant hope. The disciples do not fast because the wedding has begun; the age they were waiting for has arrived in the one speaking.</p>',
    "20": '<p>A direct revelation with passion anticipation: &ldquo;The days will come when the bridegroom is taken away from them, and then they will fast in that day.&rdquo; The &ldquo;taken away&rdquo; (apar&mdash;) is the language of violent removal — Jesus anticipates his death in this context, not abstractly but as the specific event that will end the wedding feast and begin the period of fasting. The crucifixion is the day the Bridegroom is taken; the resurrection inaugurates the new phase when fasting is again transformed by hope.</p>',
    "21": '<p>A theme of the new covenant superseding the old: no one sews a patch of unshrunk cloth on an old garment. The new cloth and old cloth image speaks to the relationship between Jesus\'s teaching and the existing scribal-Pharisaic interpretive tradition. Christ does not come to patch the old system — he brings the new covenant reality (the new cloth) that requires a new structure (the new garment). The attempt to contain his teaching within the old framework tears both.</p>',
    "22": '<p>A theme of new covenant incompatibility with old structures: new wine into old wineskins bursts the skins and the wine is lost. The new wine of the kingdom — the Spirit, the forgiveness, the Bridegroom\'s presence — cannot be contained by the old legal-ritual structures that were provisional and preparatory. Christ is not the final reform of the old system; he is the fulfillment that replaces it. The new wineskins are the new covenant community formed around him.</p>',
    "23": '<p>A theme of Christ and the Sabbath: Jesus goes through grainfields on the Sabbath and his disciples pluck heads of grain. The Sabbath setting is deliberate — it is the recurring site of conflict in Mark 2–3, because the Sabbath is the supreme sign of the Mosaic covenant (Exod 31:13–17). Christ\'s authority over the Sabbath is the specific form in which his authority over the Law is expressed.</p>',
    "24": '<p>A theme of Christological challenge: the Pharisees accuse the disciples of doing what is not lawful on the Sabbath. The charge reveals the interpretive framework in conflict: rabbinic halakha prohibited reaping and threshing (which the plucking and rubbing approximated) on Sabbath. Jesus\'s response (vv.25–28) does not deny the Sabbath\'s importance but transcends the halakhic framework with a Christological claim.</p>',
    "25": '<p>A type: David and his companions eating the showbread (1 Sam 21:1–6) is a type of Christ and his disciples. David, the anointed king fleeing persecution, ate what was lawful only for priests — his royal status created an exception that the law itself accommodated. Jesus is the greater David, the anointed Son (1:11); if David\'s need overrode the Sabbath restriction on showbread, how much more does the Son of Man\'s presence reorder the Sabbath\'s application.</p>',
    "26": '<p>A type fulfilled: David\'s entry into the house of God and eating the bread of the Presence under Abiathar the high priest — the priestly bread given to the hungry king prefigures the greater King who provides the bread of the new covenant (14:22). The type also establishes the principle Jesus is developing: royal/messianic necessity creates a different relationship to the cultic law than ordinary circumstance does.</p>',
    "27": '<p>A revelation of God\'s intention through Christ: &ldquo;The Sabbath was made for man, not man for the Sabbath.&rdquo; Christ speaks as the authoritative interpreter of creation ordinance — he knows the Sabbath\'s purpose because he is the one through whom the Sabbath was established (Col 1:16; John 1:3). The interpretive authority he exercises here is the same authority that will be claimed explicitly in v.28: he is Lord of the Sabbath, therefore he knows what the Sabbath means.</p>',
    "28": '<p>A direct revelation: &ldquo;The Son of Man is Lord even of the Sabbath.&rdquo; The Sabbath, the supreme sign of the Mosaic covenant and the seventh-day rest of creation (Gen 2:2–3; Exod 20:8–11), is under the authority of the Son of Man. The one who rested on the seventh day is the one speaking; Christ\'s lordship over the Sabbath is lordship over the creation ordinance that only the Creator can properly claim. The Sabbath finds its fulfillment in him — the eternal rest he provides (Heb 4:9–10) is what the seventh day always pointed toward.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'mark')
    merge_comm(existing, MARK_CH1_2)
    save_comm('mkt-christ', 'mark', existing)
    ch1 = len(existing.get('1', {}))
    ch2 = len(existing.get('2', {}))
    print(f'Mark 1: {ch1} verses, Mark 2: {ch2} verses.')

if __name__ == '__main__':
    main()
